import{p as t,bh as a,I as i,U as o}from"./chunks/framework.BpabEsSf.js";const m=JSON.parse('{"title":"ドキュメントマップ","description":"","frontmatter":{"title":"ドキュメントマップ","date":"2025-05-01T23:00:00.000Z","permalink":"/reference/catalogue"},"headers":[],"relativePath":"ja/02.Configuration/01.Documentation Map.md","filePath":"ja/02.Configuration/01.Documentation Map.md","lastUpdated":null}'),n={name:"ja/02.Configuration/01.Documentation Map.md"};function r(l,e,d,c,s,h){return a(),i("div",null,[...e[0]||(e[0]=[o('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /ja\\02.Configuration\\01.Documentation Map.md for this page in Markdown format</div><h1 id="🗺️-monica-全体ドキュメントマップ" tabindex="-1">🗺️ Monica 全体ドキュメントマップ <a class="header-anchor" href="#🗺️-monica-全体ドキュメントマップ" aria-label="Permalink to &quot;🗺️ Monica 全体ドキュメントマップ&quot;">​</a></h1><div class="note custom-block"><p class="title note-title custom-block-title">概要</p><p><code>Monica</code> ローカルパスワードマネージャーの公式ドキュメントセンターへようこそ。このページでは、パスワードマネージャーのエコシステム全体のシステムアーキテクチャ、コアガイド、および開発仕様への迅速なアクセスルートを提供します。</p></div><h2 id="🚀-01-入門とガイド-guide" tabindex="-1">🚀 01. 入門とガイド (Guide) <a class="header-anchor" href="#🚀-01-入門とガイド-guide" aria-label="Permalink to &quot;🚀 01. 入門とガイド (Guide)&quot;">​</a></h2><p>本セクションでは、プロジェクトの基本紹介、全体的な設計理念、および一般ユーザー向けの日常的な利用手順を案内します。</p><ul><li><strong><a href="/ja/guide/intro.html">📖 プロジェクト紹介</a></strong> * <em>Bitwarden と KeePass を統合したローカル優先のパスワードマネージャー。全般的な機能のハイライト、オープンソースへの謝辞、および資産の表記。</em></li><li><strong><a href="/ja/guide/overview.html">🎯 機能総覧</a></strong> * <em>クライアントおよびブラウザ拡張機能のコア機能の境界、および UI レイアウトを迅速に把握できます。</em></li><li><strong><a href="/ja/guide/quarkstart.html">📝 クイックスタート</a></strong> * <em>ゼロから Monica を迅速に使いこなすためのスタートガイド。</em></li></ul><h2 id="🛠️-02-開発者と技術仕様-developer-specifications" tabindex="-1">🛠️ 02. 開発者と技術仕様 (Developer Specifications) <a class="header-anchor" href="#🛠️-02-開発者と技術仕様-developer-specifications" aria-label="Permalink to &quot;🛠️ 02. 開発者と技術仕様 (Developer Specifications)&quot;">​</a></h2><p>オープンソースの貢献者、二次開発者、およびデータプライバシーの監査に関心を持つヘビーユーザー向けのセクションです。</p><ul><li><strong><a href="/ja/reference/webdav-backup-specification.html">📦 WebDAV バックアップ形式仕様</a></strong> * <em>デバイス間同期のデータストリームを解読！標準 <code>.zip</code> と暗号化された <code>.enc.zip</code> のアーカイブディレクトリツリー、JSON フィールドの詳細説明、AES-256-GCM 暗号化パイプライン、およびカスケードフォールバック復元ロジック。</em></li><li><strong><a href="/ja/reference/android-storage-security.html">🔄 ローカルストレージと暗号化技術ドキュメント</a></strong> * <em>ローカルストレージの実装ディテールと高度な暗号化セキュリティ仕様に関する技術ドキュメント。</em></li></ul><h2 id="📈-プロジェクトの進化ステータス" tabindex="-1">📈 プロジェクトの進化ステータス <a class="header-anchor" href="#📈-プロジェクトの進化ステータス" aria-label="Permalink to &quot;📈 プロジェクトの進化ステータス&quot;">​</a></h2><div class="center tk-center-container"><table tabindex="0"><thead><tr><th style="text-align:center;">現在のコアバージョン</th><th style="text-align:center;">デプロイプラットフォーム要件</th><th style="text-align:center;">オープンソースライセンス</th></tr></thead><tbody><tr><td style="text-align:center;"><code>v1.4.0</code></td><td style="text-align:center;">Android 8.0+ / Web</td><td style="text-align:center;"><a href="./LICENSE.html">GNU GPL v3.0</a></td></tr></tbody></table></div>',11)])])}const p=t(n,[["render",r]]);export{m as __pageData,p as default};
